      results[path] = await collection.aggregate(pipeline).toArray();  
    }  

    return results;  
  } catch (error) {  
    console.error("Error during vector search:", error);  
  } finally {  
    await client.close();  
    console.log("MongoDB connection closed");  
  }  
}  

